function OnlineStatus() {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  useEffect(() => {
    function handleOnline() { setIsOnline(true); }
    function handleOffline() { setIsOnline(false); }
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);
  return <div>{isOnline ? 'Online' : 'Offline'}</div>;
}

class DataFetcher extends React.Component {
  constructor(props) { super(props); this.state = { data: null, loading: true }; }
  componentDidMount() { this.fetchData(this.props.url); }
  componentDidUpdate(prevProps) { if (prevProps.url !== this.props.url) this.fetchData(this.props.url); }
  componentWillUnmount() { if (this.abortController) this.abortController.abort(); }
  async fetchData(url) {
    this.abortController = new AbortController();
    try {
      const res = await fetch(url, { signal: this.abortController.signal });
      const data = await res.json();
      this.setState({ data, loading: false });
    } catch (err) { if (err.name !== 'AbortError') this.setState({ error: err, loading: false }); }
  }
  render() { return this.state.loading ? <div>Loading...</div> : <div>{this.state.data}</div>; }
}
